// ===================================================
// WF-15 Step 1: POST 본문 파싱 + 입력값 검증 + XSS 방지
// 필수: member_id, class_id, rating(1-5), content(20자+), reviewer_name
// ===================================================

const input = $input.first().json;
const body = input.body || input;

// === 텍스트 정제 (제어 문자 제거 + 길이 제한) ===
function sanitizeText(str, maxLen) {
  if (!str) return '';
  maxLen = maxLen || 500;
  return String(str)
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
    .replace(/<[^>]*>/gi, '')
    .replace(/javascript\s*:/gi, '')
    .replace(/on\w+\s*=\s*["'][^"']*["']/gi, '')
    .replace(/on\w+\s*=\s*\S+/gi, '')
    .trim()
    .substring(0, maxLen);
}

// === HTML XSS 방지 ===
function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// === 필수 필드 추출 ===
const memberId = sanitizeText(body.member_id, 100);
const classId = sanitizeText(body.class_id, 100);
const rating = parseInt(body.rating);
const content = sanitizeText(body.content, 1000);
const reviewerName = sanitizeText(body.reviewer_name, 100);

// === 필수 필드 검증 ===
const missingFields = [];
if (!memberId) missingFields.push('member_id');
if (!classId) missingFields.push('class_id');
if (!rating || rating < 1 || rating > 5) missingFields.push('rating(1-5)');
if (!content || content.length < 20) missingFields.push('content(20자 이상)');
if (!reviewerName) missingFields.push('reviewer_name');

if (missingFields.length > 0) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'MISSING_PARAMS',
          message: missingFields.join(', ') + ' 파라미터가 필요합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _valid: true,
    memberId,
    classId,
    rating,
    content,
    reviewerName,
    _safe: {
      content: escapeHtml(content),
      reviewerName: escapeHtml(reviewerName)
    }
  }
}];

// ===================================================
// WF-15 Step 3: 예약 확인 + 중복 확인 결과 분기
// 순차 실행: Check Booking → Check Duplicate Review → 이 노드
// ===================================================

const bookingResult = $('Check Booking').first().json;
const duplicateResult = $input.first().json;
const validData = $('Validate Input').first().json;

// 예약(수강) 기록 확인
const bookingList = bookingResult.list || [];
if (bookingList.length === 0) {
  return [{
    json: {
      _canReview: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'NO_BOOKING_RECORD',
          message: '수강 이력이 확인되지 않습니다. 수강 완료 후 후기를 작성할 수 있습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// 중복 후기 확인
const reviewList = duplicateResult.list || [];
if (reviewList.length > 0) {
  return [{
    json: {
      _canReview: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'ALREADY_REVIEWED',
          message: '이미 작성한 후기가 있습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// 파트너 코드 추출 (정산에서)
const booking = bookingList[0];
const partnerCode = booking.partner_code || '';

// 리뷰 ID 생성: RV_YYYYMMDD_XXXXXX
const now = new Date();
const dateStr = now.toISOString().slice(0, 10).replace(/-/g, '');
const randomPart = Math.random().toString(36).substring(2, 8).toUpperCase();
const reviewId = 'RV_' + dateStr + '_' + randomPart;

return [{
  json: {
    _canReview: true,
    reviewId,
    classId: validData.classId,
    memberId: validData.memberId,
    reviewerName: validData.reviewerName,
    rating: validData.rating,
    content: validData.content,
    partnerCode,
    safeContent: validData._safe ? validData._safe.content : '',
    safeReviewerName: validData._safe ? validData._safe.reviewerName : ''
  }
}];

// ===================================================
// WF-15 Step 5: 성공 응답 생성
// ===================================================

const decisionData = $('Decision').first().json;
const incentiveResult = $input.first().json;

// 적립금 지급 결과 확인 (실패해도 후기 자체는 성공)
let incentiveSuccess = false;
let incentiveMessage = '';

try {
  if (incentiveResult && (incentiveResult.result === 'success' || incentiveResult.OK === 'Y')) {
    incentiveSuccess = true;
    incentiveMessage = '적립금 1,000원 지급 완료';
  } else {
    incentiveMessage = '적립금 지급 실패 (후기는 정상 등록됨)';
    console.log('[WF-15] 적립금 API 응답:', JSON.stringify(incentiveResult));
  }
} catch (e) {
  incentiveMessage = '적립금 지급 확인 불가';
}

return [{
  json: {
    _successResponse: {
      success: true,
      data: {
        review_id: decisionData.reviewId,
        class_id: decisionData.classId,
        member_id: decisionData.memberId,
        rating: decisionData.rating,
        incentive: {
          granted: incentiveSuccess,
          amount: 1000,
          message: incentiveMessage
        }
      },
      timestamp: new Date().toISOString()
    }
  }
}];
